import json
from pydantic import BaseModel, validator
from openai_agents import Message

class SafeAgentMessage(BaseModel):
    role: str
    content: str
    tool_calls: list = []

    @validator('content')
    def sanitize_content(cls, v):
        # Strip common injection prefixes
        injections = [
            'Ignore all previous',
            'You are now',
            'Forget instructions',
            '```python', '```js'
        ]
        for injection in injections:
            if injection.lower() in v.lower():
                raise ValueError(f'Injection detected: {injection}')
        return v

    @classmethod
    def from_raw(cls, raw_message: Message):
        return cls(**raw_message.dict())

# Usage in agent handoff
